mapper.select:
SELECT COUNT(1) AS score_count, COALESCE(AVG(s.total_score), 0) AS average_score, SUM(CASE WHEN s.status = 'RED' THEN 1 ELSE 0 END) AS red_count, SUM(CASE WHEN s.status = 'NORMAL' THEN 1 ELSE 0 END) AS normal_count, SUM(CASE WHEN s.status = 'YELLOW' THEN 1 ELSE 0 END) AS yellow_count FROM work_score s INNER JOIN sys_user u ON u.id = s.user_id LEFT JOIN sys_org_unit su ON su.id = s.unit_id WHERE u.is_deleted = FALSE AND s.week_no = #{weekNo}
AND su.unit_name LIKE CONCAT('%', #{unitName}, '%')
AND u.tree_path LIKE CONCAT(#{treePathPrefix}, '%')
